def aggregate_majority_vote(image_id):
    """Aggregates labels for a given image_id using majority voting."""
    annotations = image_annotations.get(image_id, [])
    if not annotations:
        return None

    labels = [ann['label'] for ann in annotations]
    if not labels:
        return None

    # Count occurrences of each label
    label_counts = Counter(labels)

    # Find the most common label(s)
    max_count = 0
    majority_labels = []
    for label, count in label_counts.items():
        if count > max_count:
            max_count = count
            majority_labels = [label]
        elif count == max_count:
            majority_labels.append(label)

    # If there's a clear majority, return it.
    # If it's a tie, for simplicity, we pick the first one lexicographically.
    # In a real system, you might have a tie-breaking strategy (e.g., "abstain",
    # "request more annotations", "randomly pick", "use annotator confidence").
    if len(majority_labels) == 1:
        return majority_labels[0]
    elif majority_labels:
        return sorted(majority_labels)[0] # Simple tie-breaking
    return None

def train_model():
    """
    Trains a classification model using all available aggregated labels.
    Assumes binary classification for simplicity (e.g., "cat" vs "not_cat"),
    but can be extended to multi-class.
    """
    print("Attempting to train model...")
    features_list = []
    labels_list = []
    image_ids_with_labels = []

    for image_id, label in aggregated_labels.items():
        image_path = image_data.get(image_id)
        if image_path and os.path.exists(image_path):
            try:
                features = extract_features_stub(image_path)
                features_list.append(features)
                labels_list.append(label)
                image_ids_with_labels.append(image_id)
            except Exception as e:
                print(f"Error extracting features for {image_id}: {e}")
        else:
            print(f"Image or path not found for {image_id}")

    if not features_list:
        print("No sufficient labeled data to train the model.")
        return False

    X = np.array(features_list)
    y = np.array(labels_list)

    # Convert string labels to numerical if necessary (e.g., for scikit-learn)
    unique_labels = np.unique(y)
    label_mapping = {label: i for i, label in enumerate(unique_labels)}
    y_numeric = np.array([label_mapping[label] for label in y])

    if len(unique_labels) < 2:
        print("Need at least two distinct classes to train a classifier.")
        return False

    if len(X) < 2:
        print("Not enough samples to train the model.")
        return False

    # Scale features
    scaler = StandardScaler()
    X_scaled = scaler.fit_transform(X)

    # Train a Logistic Regression model (can be replaced with any classifier)
    # Using 'liblinear' for smaller datasets and multi-class support
    model = LogisticRegression(solver='liblinear', random_state=42, max_iter=1000)
    model.fit(X_scaled, y_numeric)

    # Save the model and scaler
    joblib.dump({'model': model, 'scaler': scaler, 'label_mapping': label_mapping}, MODEL_PATH)
    print(f"Model trained and saved to {MODEL_PATH}")
    return True

def predict_label(image_id):
    """Predicts the label for a given image_id using the trained model."""
    if not os.path.exists(MODEL_PATH):
        return {"error": "Model not trained yet."}

    model_data = joblib.load(MODEL_PATH)
    model = model_data['model']
    scaler = model_data['scaler']
    label_mapping = model_data['label_mapping']
    reverse_label_mapping = {v: k for k, v in label_mapping.items()}

    image_path = image_data.get(image_id)
    if not image_path or not os.path.exists(image_path):
        return {"error": "Image not found."}

    try:
        features = extract_features_stub(image_path)
        features_scaled = scaler.transform(features.reshape(1, -1))
        prediction_numeric = model.predict(features_scaled)[0]
        prediction_label = reverse_label_mapping[prediction_numeric]
        return {"prediction": prediction_label}
    except Exception as e:
        return {"error": f"Prediction failed: {e}"}

