@app.route('/upload_image', methods=['POST'])
def upload_image():
    """
    Uploads an image, saves it, and generates a unique ID.
    Expects 'image' as a file in the form-data.
    """
    if 'image' not in request.files:
        return jsonify({"error": "No image file provided"}), 400

    image_file = request.files['image']
    if image_file.filename == '':
        return jsonify({"error": "No selected image file"}), 400

    if image_file:
        image_id = str(uuid.uuid4())
        filename = f"{image_id}.png" # Assuming png for simplicity, can infer from mimetype
        filepath = os.path.join(IMAGE_DIR, filename)

        try:
            # Ensure it's a valid image and save
            img = Image.open(image_file.stream)
            img.save(filepath)
            image_data[image_id] = filepath
            save_data() # Persist image_data in a real app
            return jsonify({"message": "Image uploaded successfully", "image_id": image_id}), 201
        except Exception as e:
            return jsonify({"error": f"Failed to process image: {e}"}), 500

@app.route('/annotate', methods=['POST'])
def annotate_image():
    """
    Submits an annotation for a specific image.
    Expects 'image_id', 'annotator_id', and 'label' in the JSON body.
    """
    data = request.get_json()
    image_id = data.get('image_id')
    annotator_id = data.get('annotator_id')
    label = data.get('label')

    if not all([image_id, annotator_id, label]):
        return jsonify({"error": "Missing image_id, annotator_id, or label"}), 400

    if image_id not in image_data:
        return jsonify({"error": "Image ID not found"}), 404

    image_annotations[image_id].append({"annotator_id": annotator_id, "label": label})
    save_data() # Persist image_annotations in a real app

    # Trigger aggregation and potential re-training
    aggregated_label = aggregate_majority_vote(image_id)
    if aggregated_label:
        aggregated_labels[image_id] = aggregated_label
        print(f"Aggregated label for {image_id}: {aggregated_label}")
        # Automatically re-train the model if a new aggregated label is available
        train_model()
    else:
        print(f"Not enough annotations for {image_id} to aggregate yet.")


    return jsonify({"message": "Annotation submitted successfully", "image_id": image_id, "current_annotations_count": len(image_annotations[image_id])}), 201

